mapper.select:

where 1=1

    AND s.submit_id = #{submitId}


    AND s.homework_id = #{homeworkId}


    AND s.student_id = #{studentId}


    AND s.status = #{status}


    AND st.student_name like concat('%', #{studentName}, '%')


    AND st.admission_year = #{admissionYear}


    AND st.class_num = #{classNum}

order by s.submit_time desc

mapper.update:
update stu_homework_submit
file_name = #{fileName}, score = #{score}, comment = #{comment}, status = #{status}, update_time = sysdate()
where submit_id = #{submitId}

mapper.select:
select s.submit_id, s.homework_id, st.student_id, s.file_name,
       CONCAT(h.storage_path, '/', s.file_name) as file_path,
       s.submit_time, s.score, s.comment, s.status,
       s.create_time, s.update_time,
       st.student_name, st.account, h.title as homework_title
from stu_student st
left join stu_homework_submit s on s.student_id = st.student_id and s.homework_id = #{homeworkId}
left join stu_homework h on h.homework_id = #{homeworkId}
where st.del_flag = '0'
 AND st.admission_year = #{admissionYear} 
 AND st.class_num = #{classNum} 
 AND st.student_name like concat('%', #{studentName}, '%') 
order by st.student_num asc
